sql:
SELECT skill_name, category
FROM skills
ORDER BY skill_name ASC;

SELECT average_effectiveness AS avg_effectiveness
  FROM skill_statistics
  WHERE skill_id = 1;

SELECT buff_name
  FROM buffs
  WHERE is_renewable = 1 AND duration > 10;

SELECT skill_id, average_effectiveness
FROM skill_statistics
WHERE skill_id = 0;

SELECT buff_name, MAX(duration) AS max_duration
FROM buffs
GROUP BY buff_name;

SELECT average_effectiveness
FROM buff_statistics
WHERE buff_id = 0;

SELECT skill_name
FROM skills
WHERE cooldown_time = (SELECT MAX(cooldown_time) FROM skills);

SELECT skill_id
FROM skill_statistics
WHERE average_effectiveness = (SELECT MAX(average_effectiveness) FROM skill_statistics);

external_knowledge:
- In the context of this game, skills are hierarchical, meaning some skills depend on others to be used; 
- The average effectiveness of a skill refers to its overall impact or usefulness in the game; 
- A player's proficiency level in a skill represents their mastery or expertise in using that skill; 
- Synergistic skills are skills that work well together or enhance each other's effects; 
- Cumulative proficiency refers to the total proficiency a player has across all their skills.
